CREATE TABLE `calendar_items` (
  `id` varchar(191) NOT NULL,
  `title` varchar(191) NOT NULL,
  `description` text DEFAULT NULL,
  `startTime` datetime(3) NOT NULL,
  `endTime` datetime(3) NOT NULL,
  `isAllDay` tinyint(1) NOT NULL DEFAULT 0,
  `itemType` enum('TASK_DEADLINE','MEETING','EVENT','BREAK','VACATION','TRAINING','CLIENT_CALL','MILESTONE') NOT NULL DEFAULT 'EVENT',
  `taskId` varchar(191) DEFAULT NULL,
  `projectId` varchar(191) DEFAULT NULL,
  `createdById` varchar(191) NOT NULL,
  `workspaceCalendarId` varchar(191) NOT NULL,
  `color` varchar(191) NOT NULL DEFAULT '#3B82F6',
  `priority` enum('LOW','MEDIUM','HIGH','URGENT') NOT NULL DEFAULT 'MEDIUM',
  `status` enum('SCHEDULED','IN_PROGRESS','COMPLETED','CANCELLED','POSTPONED') NOT NULL DEFAULT 'SCHEDULED',
  `createdAt` datetime(3) NOT NULL DEFAULT current_timestamp(3),
  `updatedAt` datetime(3) NOT NULL,
  PRIMARY KEY (`id`),
  KEY `calendar_items_workspaceCalendarId_idx` (`workspaceCalendarId`),
  KEY `calendar_items_createdById_idx` (`createdById`),
  KEY `calendar_items_taskId_idx` (`taskId`),
  KEY `calendar_items_projectId_idx` (`projectId`),
  KEY `calendar_items_startTime_idx` (`startTime`),
  KEY `calendar_items_endTime_idx` (`endTime`),
  CONSTRAINT `calendar_items_createdById_fkey` FOREIGN KEY (`createdById`) REFERENCES `users` (`id`) ON UPDATE CASCADE,
  CONSTRAINT `calendar_items_projectId_fkey` FOREIGN KEY (`projectId`) REFERENCES `projects` (`id`) ON DELETE SET NULL ON UPDATE CASCADE,
  CONSTRAINT `calendar_items_taskId_fkey` FOREIGN KEY (`taskId`) REFERENCES `tasks` (`id`) ON DELETE SET NULL ON UPDATE CASCADE,
  CONSTRAINT `calendar_items_workspaceCalendarId_fkey` FOREIGN KEY (`workspaceCalendarId`) REFERENCES `workspace_calendars` (`id`) ON DELETE CASCADE ON UPDATE CASCADE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;
