DROP TABLE IF EXISTS `projects`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `projects` (
  `id` varchar(191) NOT NULL,
  `name` varchar(191) NOT NULL,
  `description` varchar(191) DEFAULT NULL,
  `workspaceId` varchar(191) NOT NULL,
  `status` enum('ACTIVE','ON_HOLD','COMPLETED','ARCHIVED') NOT NULL DEFAULT 'ACTIVE',
  `priority` enum('LOW','MEDIUM','HIGH','URGENT') NOT NULL DEFAULT 'MEDIUM',
  `startDate` datetime(3) DEFAULT NULL,
  `dueDate` datetime(3) DEFAULT NULL,
  `createdBy` varchar(191) NOT NULL,
  `createdAt` datetime(3) NOT NULL DEFAULT current_timestamp(3),
  `updatedAt` datetime(3) NOT NULL,
  `departmentId` varchar(191) DEFAULT NULL,
  `clientId` varchar(191) DEFAULT NULL,
  `projectType` enum('FIXED_TERM','ONGOING') NOT NULL DEFAULT 'FIXED_TERM',
  `zohoFolderLink` varchar(191) DEFAULT NULL,
  `internalProductId` varchar(191) DEFAULT NULL,
  `isClientProject` tinyint(1) NOT NULL DEFAULT 0,
  `notes` longtext CHARACTER SET utf8mb4 COLLATE utf8mb4_bin DEFAULT NULL CHECK (json_valid(`notes`)),
  `projectCode` varchar(191) DEFAULT NULL,
  PRIMARY KEY (`id`),
  UNIQUE KEY `projects_name_key` (`name`),
  UNIQUE KEY `projects_projectCode_key` (`projectCode`),
  KEY `projects_workspaceId_fkey` (`workspaceId`),
  KEY `projects_createdBy_fkey` (`createdBy`),
  KEY `projects_departmentId_fkey` (`departmentId`),
  KEY `projects_clientId_fkey` (`clientId`),
  KEY `projects_internalProductId_fkey` (`internalProductId`),
  CONSTRAINT `projects_clientId_fkey` FOREIGN KEY (`clientId`) REFERENCES `users` (`id`) ON DELETE SET NULL ON UPDATE CASCADE,
  CONSTRAINT `projects_createdBy_fkey` FOREIGN KEY (`createdBy`) REFERENCES `users` (`id`) ON UPDATE CASCADE,
  CONSTRAINT `projects_departmentId_fkey` FOREIGN KEY (`departmentId`) REFERENCES `departments` (`id`) ON DELETE SET NULL ON UPDATE CASCADE,
  CONSTRAINT `projects_internalProductId_fkey` FOREIGN KEY (`internalProductId`) REFERENCES `InternalProduct` (`id`) ON DELETE SET NULL ON UPDATE CASCADE,
  CONSTRAINT `projects_workspaceId_fkey` FOREIGN KEY (`workspaceId`) REFERENCES `workspaces` (`id`) ON DELETE CASCADE ON UPDATE CASCADE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;
/*!40101 SET character_set_client = @saved_cs_client */;

--
-- Dumping data for table `projects`
--

LOCK TABLES `projects` WRITE;
/*!40000 ALTER TABLE `projects` DISABLE KEYS */;
