--
-- Table structure for table `tasks`
--

DROP TABLE IF EXISTS `tasks`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `tasks` (
  `id` varchar(191) NOT NULL,
  `title` varchar(191) NOT NULL,
  `description` varchar(191) DEFAULT NULL,
  `projectId` varchar(191) NOT NULL,
  `assigneeId` varchar(191) DEFAULT NULL,
  `reporterId` varchar(191) NOT NULL,
  `position` int(11) NOT NULL,
  `priority` enum('LOW','MEDIUM','HIGH','URGENT') NOT NULL DEFAULT 'MEDIUM',
  `status` enum('TO_DO','IN_PROGRESS','REVIEW','DONE') NOT NULL DEFAULT 'TO_DO',
  `startDate` datetime(3) DEFAULT NULL,
  `dueDate` datetime(3) DEFAULT NULL,
  `createdAt` datetime(3) NOT NULL DEFAULT current_timestamp(3),
  `updatedAt` datetime(3) NOT NULL,
  `departmentId` varchar(191) DEFAULT NULL,
  `taskCode` varchar(191) DEFAULT NULL,
  `taskType` enum('TASK','BUG','FEATURE','IMPROVEMENT','EPIC') DEFAULT 'TASK',
  `actualMinutes` int(11) NOT NULL DEFAULT 0,
  `completedAt` datetime(3) DEFAULT NULL,
  `estimatedMinutes` int(11) DEFAULT NULL,
  PRIMARY KEY (`id`),
  UNIQUE KEY `tasks_taskCode_key` (`taskCode`),
  KEY `tasks_projectId_fkey` (`projectId`),
  KEY `tasks_assigneeId_fkey` (`assigneeId`),
  KEY `tasks_reporterId_fkey` (`reporterId`),
  KEY `tasks_departmentId_fkey` (`departmentId`),
  CONSTRAINT `tasks_assigneeId_fkey` FOREIGN KEY (`assigneeId`) REFERENCES `users` (`id`) ON DELETE SET NULL ON UPDATE CASCADE,
  CONSTRAINT `tasks_departmentId_fkey` FOREIGN KEY (`departmentId`) REFERENCES `departments` (`id`) ON DELETE SET NULL ON UPDATE CASCADE,
  CONSTRAINT `tasks_projectId_fkey` FOREIGN KEY (`projectId`) REFERENCES `projects` (`id`) ON DELETE CASCADE ON UPDATE CASCADE,
  CONSTRAINT `tasks_reporterId_fkey` FOREIGN KEY (`reporterId`) REFERENCES `users` (`id`) ON UPDATE CASCADE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;
/*!40101 SET character_set_client = @saved_cs_client */;

